// // This module implements a master-slave D-latch where the master captures the input on the falling edge of the clock and the slave outputs the captured value on the rising edge.
module master_slave_d_latch (  
    input wire D,  
    input wire CLK,  
    output reg Q  
);  
    reg master;  
    always @(posedge CLK) begin  
        master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= master;  
    end  
endmodule
